solution_code:
#include <iostream>

class Point {
    const int m_x;
    const int m_y;
public:
    Point(int x, int y)
        : m_x{ x }, m_y{ y }
    {}

    int getX() const { return m_x; }
    int getY() const { return m_y; }
};

Point makePoint(int x, int y) {
    return Point{ x, y };
}

int main() {
    int x{}, y{};
    std::cin >> x >> y;
    Point p{ makePoint(x, y) };
    std::cout << "Point(" << p.getX() << ", " << p.getY() << ")\n";
}
